var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【부록-003】 면담기록</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05：<color=#ffd34c>【付録-003】 面談記録</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【附錄-003】 面談記錄</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR002M0011-05: <color=#ffd34c>【附錄-003】 面談記錄</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"솔저 한소림, 관리국의 호출을 받아 지금 막 도착했다.","JPN":"ソルジャー ハネダ・ミズキ、管理局の要請により、ただいま馳せ参じた​。","ENG":"Soldier Han Sorim, reporting for duty under the Administration's summon.","TWN":"軍人韓蕭林，收到管理局的呼叫，準時到達。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하하, 경례는 안 하셔도 돼요.","JPN":"ハハ、敬礼は結構ですよ。","ENG":"Hah hah, there's no need to salute.","TWN":"哈哈，不用敬禮啦。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"긴장하지 말고 앉으세요. 그냥 절차에 따른 간단한 상담만 진행할 겁니다.","JPN":"リラックスしておかけ下さい。\\nほんの手続きです。簡単な面談だけで済みますので。","ENG":"Try to relax and sit down. We're just going to proceed with a short protocol interview.","TWN":"不要緊張，坐下吧。我只是按照流程，跟妳做些簡單的諮詢而已。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그런데 저...... 입구에서 어떤 사람이 스미스 병장...... 아, 아니, 제 인형을 가져가던데요......","JPN":"ところで、その……入り口でスミス兵長を……\\nい、いや、お人形を取られてしまったんですが……","ENG":"But, uh... Someone took my Sergeant Smith... I-I mean, my doll at the entrance...","TWN":"但是那個……門口有人把史密斯兵長……啊，不對，是把我的娃娃拿走了……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 보안절차니까 이해해주세요. 다른 직원 분이 깔끔하게 소독해서 돌려드릴 겁니다.","JPN":"それも保安上の手続きでして、ご理解いただければ幸いです。\\n他の職員がきれいに消毒してお返しいたしますよ。","ENG":"Oh, it's just a security measure. The other employee will return it to you after having it sanitized.","TWN":"啊，那是安全流程，請理解一下。其他的員工消毒乾淨後會還給妳的。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그보다 소림 양은 지금 가족들과 떨어져 지내고 있는데, 외롭진 않나요?","JPN":"それより、ハネダさんは今ご家族と離れて\\n暮らしておられますが、寂しかったりはしませんか？","ENG":"By the way, Sorim. I see that you're living away from your family. Don't you feel lonely at all?","TWN":"先不說這些了。蕭林妳會不會因為和家人分開住，所以感到寂寞呢？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"ENG":"A little bit...","TWN":"稍微有點……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"조금은......","JPN":"ちょっとだけ……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그, 그래도 하림 언니가 있으니까, 괜찮다. 친구들도 많이 있고......","JPN":"で、でも、ウサギ隊長がいるから、平気だ。友達だってたくさんいるし……","ENG":"B-but it's okay since I have Harim with me. And I have a lot of friends...","TWN":"但、但是有夏琳姐姐陪著我，所以沒關係。而且我還交到了很多朋友……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니, 소림 양은 자신이...... 음...... 베테랑 군인이라고 주장하시는데요.","JPN":"そういえば、ハネダさんは……ご自身のことを、\\nその……ベテラン軍人だと主張なさっていますね。","ENG":"So, Sorim, you claim to be... um... a veteran soldier?","TWN":"這麼說來，蕭林小姐好像……呃……宣稱自己是老兵的樣子？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"주장이 아니다! 사실을 이야기 한 것뿐이지.","JPN":"主張ではない！　事実を述べているだけだ。","ENG":"It's not a claim! I'm just stating facts.","TWN":"不是宣稱！我只不過陳述事實而已！"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"네, 알겠습니다. 그렇다고 치고요. 소림 양은 그럼 언제부터 군인이 되신 거죠?","JPN":"ええ、承知しました。そういうことにしておきましょう。\\nそれで、あなたはいつから軍人になられたのです？","ENG":"Yes, I understand. We'll say that's true. Then, Sorim, when did you join the military?","TWN":"是，我知道了，就當作是那樣吧。那蕭林小姐是從什麼時候開始從軍的？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그건...... 그러니까......","JPN":"それは……その……","ENG":"That's... Uh...","TWN":"這……所以說……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어렸을 때...... 난 병원에서 살고 있었다.","JPN":"子供の頃……本官は病院で暮らしていた。","ENG":"When I was young... I was living at a hospital.","TWN":"小時候……我一直都住在醫院。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그때 난 거의 움직이지를 못해서...... 밖에 나가는 대신 아빠가 찍어온 사진들을 보면서 노는 게 일상이었다.","JPN":"あの頃、本官はほとんど体を動かせなかったから……父が外で撮ってきた\\n写真を眺めるのが日々の楽しみだったのだ。","ENG":"I could barely move back then... So instead of playing outside, I used to play with the photographs my dad brought me.","TWN":"那時候我幾乎不能動……沒辦法出去玩，所以看著爸爸拍的照片玩耍，就是我的日常。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 아버님이...... 종군 기자셨던 것 같군요.","JPN":"そういえば、お父様は……従軍記者をされていたとか。","ENG":"I see that you're father... was a war correspondent.","TWN":"說到這個，妳的父親似乎……是一名從軍記者吧。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"군수 장비 쪽 칼럼도 많이 쓰시고 경력이 화려하신 분 같은데 지금은...... 음?","JPN":"軍需品に関する記事を何件も書かれていて、\\n派手な経歴をお持ちのようですが、今は……ん？","ENG":"He wrote a lot of columns regarding military equipment with an incredible career. But right now... Huh?","TWN":"他在軍事裝備方面有大量的專欄，是一位事業成功的人呢，而現在……嗯？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"이런 실례, 지금은 어머님과 이혼을 하셨군요.","JPN":"おっと、失礼。今はお母様と離婚されたのでしたか。","ENG":"I'm sorry, your father and mother are divorced now?","TWN":"這真是失禮了，他現在好像跟妳母親離婚了。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"어, 어쨌든 그래서 아빠가 보여준 사진에 있는 것처럼 강하고 절도 있는 군인이 되기로 결심했다.","JPN":"と、とにかく、父に見せてもらった写真に映っていたような、\\n強くて凛々しい軍人になると、そう決心したのだ。","ENG":"A-anyway, I decided to become a soldier, inspired by the strong and disciplined soldiers in my father's photos.","TWN":"所、所以不管怎樣，我都決定要成為堅強又勇敢的軍人，就像爸爸給我看的照片一樣。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"단련의 성과인지 그때부터 몸도 많이 좋아져서 보다시피 지금은 심판의 방아쇠라는 명성을 드높이고 있지.","JPN":"鍛練の成果もあってか、その頃から体もだいぶ良くなった。\\nそして見ての通り、今では審判の引き金という勇名を馳せるに至ったのだ。","ENG":"My body soon recovered after going through intense training. And now, I am gaining fame as the Trigger of Judgment.","TWN":"也不知道是不是鍛煉的成果，從那時候，我的身體就變好了很多。然後如你所見，我還因為稱號“審判的扳機”而聲名大噪。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"조금만 더 단련을 하면 아빠가...... 내 사진을 찍으러 와 줄지도......","JPN":"もう少し鍛練を積めば父が……\\n本官の写真を撮りに来てくれるかも……","ENG":"If I just train a bit more, my dad might... he might come take my pictures...","TWN":"只要再鍛鍊一下……爸爸說不定就會來幫我拍照……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"요약하면 소림 양이 카운터로 각성하게 된 계기는 <color=#ffd34c>아빠의 관심을 끌기 위해서</color> 인가요?","JPN":"要するにハネダさんがカウンターとして覚醒を果たしたきっかけは、<color=#ffd34c>お父様の気を引くため</color>なのですね？","ENG":"So, in summary, you awakened your power as a Counter in order to <color=#ffd34c>gain attention from your father</color>?","TWN":"總而言之，蕭林小姐覺醒成制裁者的契機，是為了<color=#ffd34c>引起爸爸的注意</color> 嗎？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......그게 무슨 말이지? 본관은 카운터 각성 같은 걸 경험한 적이 없다네.","JPN":"……何を言っている？ 本官はカウンターに覚醒など経験した覚えはないぞ。","ENG":"What do you mean by that? I never awakened my power as a Counter.","TWN":"……你在說什麼？本官從來沒有覺醒成制裁者的經驗。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그저 총 한 자루에 의지해 싸우는 평범한 군인일 뿐.","JPN":"本官は一丁の銃に\\n命を預けて戦う、ただのしがない軍人なのだ。","ENG":"I'm just a soldier who relies upon her rifle in battle.","TWN":"我只是依靠槍來戰鬥的普通士兵而已。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"본인이 카운터인 걸 부정해버리면, 앞으로는 지원금을 지급하기가 곤란한데요.","JPN":"ご本人がカウンターであることを\\n否定なさいますと、今後は補助金の支給が難しくなるのですが。","ENG":"If you deny that you're a Counter, it would be hard for us to give support funding.","TWN":"如果妳否認自己是制裁者，那我們以後會很難提供支援金給妳。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"흐, 흐그그...... 아, 아빠한테 잘 보이기 위해서가 맞는 것 같아요오.......","JPN":"うっ、うぐぐっ……お、父さんの気を引きたいから……それで合ってると、思いますぅ……","ENG":"U-ugh... I-I think it was to gain my dad's attention as well...","TWN":"哇，哇啊啊啊……我、我好像真的是為了引起爸爸的注意……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"음, 잘 알겠습니다. 상담은 이것으로 마치죠.","JPN":"よくわかりました。\\n面談はこれにて終わらせていただきます。","ENG":"Mm, I understand. Well, that's should be enough.","TWN":"好的，我明白了，那這次諮詢就到此結束吧。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아까부터 곁눈질 하던데, 상담실에 비치된 과자는 얼마든지 먹어도 됩니다.","JPN":"さっきからチラチラと気にされてましたね。\\nこちらのお菓子でしたら、いくらでもご自由にどうぞ。","ENG":"I noticed that you were eyeing the snacks on the table. Feel free to help yourself.","TWN":"我看妳從剛才就一直在偷看，其實諮詢室裡的餅乾是可以隨便吃的。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그, 그런 적은 없네만...... 뭐, 그렇게까지 권한다면 사양하진 않겠네.","JPN":"気、気にしてなどいないが……そ、そこまで勧めるなら遠慮はしないでおこう。","ENG":"I-I never did such thing... But since you're offering, I won't decline.","TWN":"我、我才沒有偷看呢……不過，既然你都這麼說了，那我就不客氣了。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"자, 상담도 끝났으니 관리국 군사박물관 견학을 한 번 시켜드릴까 하는데, 어때요?","JPN":"さて、面談も済みましたので、管理局の軍事博物館の見学などは\\nいかがですか？　よろしければご案内しますよ。","ENG":"Now that the interview is over, I was thinking I would show you around the Administration Military Museum. What do you think?","TWN":"那麼，諮詢也結束了，我就帶妳參觀一下管理局的軍事博物館吧，怎麼樣？"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그, 그그 긍믈응그?! <color=#ffd34c>(그, 그게 정말인가?!)</color>","JPN":"ほ、ほへはほんほはぁ！？<color=#ffd34c>(そ、それはホントかぁ！？)</color>","ENG":"Arre u cirrous?! <color=#ffd34c>(A-are you serious?!)</color>","TWN":"鈉、鈉素蒸的嘛？！<color=#ffd34c>（那，那是真的嗎？）</color>"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하하, 듣던 대로 정말 반응이 좋으시네요. 그럼 가볼까요?","JPN":"はは、聞いていたとおり\\n良い反応をされますね。では参りましょうか。","ENG":"Hah hah, you really do give the best reactions. Shall we get going?","TWN":"哈哈，跟聽說的一樣，反應真不錯呢。那麼我們走吧。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"흠, 흠. 가끔은 시찰을 돌아보는 것도 나쁘지 않지. 앞장서게.","JPN":"お、おっほん。たまには視察も悪くないからな。君が先導したまえ。","ENG":"Ahem, Hmm. I suppose it would be nice to inspect once in a while. Lead the way.","TWN":"哼嗯，哼嗯。偶爾去視察也不錯，帶路吧。"},"stage":{"bg":"BLACK","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};